#include <omp.h>
#include <stdbool.h>

#ifndef DEFAULT_ORDER
#define DEFAULT_ORDER 256
#endif

#define fp float

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER + 1];
	int  keys [DEFAULT_ORDER + 1];
	bool is_leaf;
	int num_keys;
} knode; 

void kernel_cpu(	int cores_arg,
					record *records,
					knode *knodes,
					long knodes_elem,
					int order,
					long maxheight,
					int count,
					long *currKnode,
					long *offset,
					int *keys,
					record *ans)
{
	// Each "bid" corresponds to one query
	#pragma omp parallel for schedule(static) num_threads(cores_arg)
	for (int bid = 0; bid < count; bid++) {
		// For each level in the tree
		for(int i = 0; i < maxheight; i++){
			long currKnode_local = currKnode[bid];
			long offset_local = offset[bid];
			int key = keys[bid];

			// For each thread id (simulate thid in OpenCL)
			// We parallelize over thid here
			#pragma omp parallel for schedule(static)
			for (int thid = 0; thid < order; thid++) {
				if (thid+1 <= order) {
					if((knodes[currKnode_local].keys[thid]) <= key && (knodes[currKnode_local].keys[thid+1] > key)){
						if(knodes[offset_local].indices[thid] < knodes_elem){
							#pragma omp critical
							{
								offset[bid] = knodes[offset_local].indices[thid];
							}
						}
					}
				}
			}
			// Update currKnode for this bid
			if(omp_get_thread_num() == 0){
				currKnode[bid] = offset[bid];
			}
		}

		long currKnode_local = currKnode[bid];
		int key = keys[bid];

		// Find matching key and set answer
		#pragma omp parallel for schedule(static)
		for (int thid = 0; thid < order; thid++) {
			if(knodes[currKnode_local].keys[thid] == key){
				ans[bid].value = records[knodes[currKnode_local].indices[thid]].value;
			}
		}
	}
}

