#include <omp.h>
#include <stdbool.h>

#ifndef DEFAULT_ORDER_2
#define DEFAULT_ORDER_2 256
#endif

#define fp float

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER_2 + 1];
	int  keys [DEFAULT_ORDER_2 + 1];
	bool is_leaf;
	int num_keys;
} knode; 

void kernel_cpu_2(	int cores_arg,
					knode *knodes,
					long knodes_elem,
					int order,
					long maxheight,
					int count,
					long *currKnode,
					long *offset,
					long *lastKnode,
					long *offset_2,
					int *start,
					int *end,
					int *recstart,
					int *reclength)
{
	// Each "bid" corresponds to one query
	#pragma omp parallel for schedule(static) num_threads(cores_arg)
	for (int bid = 0; bid < count; bid++) {
		// For each level in the tree
		for(int i = 0; i < maxheight; i++){
			long currKnode_local = currKnode[bid];
			long lastKnode_local = lastKnode[bid];
			long offset_local = offset[bid];
			long offset_2_local = offset_2[bid];
			int start_local = start[bid];
			int end_local = end[bid];

			// For each thread id (simulate thid in OpenCL)
			// We parallelize over thid here
			#pragma omp parallel for schedule(static)
			for (int thid = 0; thid < order; thid++) {
				if (thid+1 <= order) {
					if((knodes[currKnode_local].keys[thid] <= start_local) && (knodes[currKnode_local].keys[thid+1] > start_local)){
						if(knodes[currKnode_local].indices[thid] < knodes_elem){
							#pragma omp critical
							{
								offset[bid] = knodes[currKnode_local].indices[thid];
							}
						}
					}
					if((knodes[lastKnode_local].keys[thid] <= end_local) && (knodes[lastKnode_local].keys[thid+1] > end_local)){
						if(knodes[lastKnode_local].indices[thid] < knodes_elem){
							#pragma omp critical
							{
								offset_2[bid] = knodes[lastKnode_local].indices[thid];
							}
						}
					}
				}
			}
			// Update currKnode and lastKnode for this bid
			if(omp_get_thread_num() == 0){
				currKnode[bid] = offset[bid];
				lastKnode[bid] = offset_2[bid];
			}
		}

		long currKnode_local = currKnode[bid];
		long lastKnode_local = lastKnode[bid];
		int start_local = start[bid];
		int end_local = end[bid];

		// Find matching start key and set recstart
		#pragma omp parallel for schedule(static)
		for (int thid = 0; thid < order; thid++) {
			if(knodes[currKnode_local].keys[thid] == start_local){
				recstart[bid] = knodes[currKnode_local].indices[thid];
			}
		}

		// Find matching end key and set reclength
		#pragma omp parallel for schedule(static)
		for (int thid = 0; thid < order; thid++) {
			if(knodes[lastKnode_local].keys[thid] == end_local){
				reclength[bid] = knodes[lastKnode_local].indices[thid] - recstart[bid] + 1;
			}
		}
	}
}
